+// runFmtCheck runs gofmt -l and fails if any files need formatting.
+func runFmtCheck() CheckResult {
+	command := "gofmt -l ."
+
+	// Check if gofmt is available
+	if _, err := exec.LookPath("gofmt"); err != nil {
+		return CheckResult{
+			Name:    "Formatting",
+			Passed:  false,
+			Output:  "gofmt not found in PATH (install Go toolchain)",
+			Command: command,
+		}
+	}
+
+	cmd := exec.Command("gofmt", "-l", ".")
+	output, err := cmd.CombinedOutput()
+
+	if err != nil {
+		return CheckResult{
+			Name:    "Formatting",
+			Passed:  false,
+			Output:  string(output),
+			Command: command,
+		}
+	}
+
+	unformatted := strings.TrimSpace(string(output))
+	if unformatted != "" {
+		return CheckResult{
+			Name:    "Formatting",
+			Passed:  false,
+			Output:  fmt.Sprintf("Unformatted files:\n%s\nRun: gofmt -w .", unformatted),
+			Command: command,
+		}
+	}
+
+	return CheckResult{
+		Name:    "Formatting",
+		Passed:  true,
+		Command: command,
+	}
+}
